INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('COSMOS_1: Le email predictive engagement: analyser les patterns d ouverture de chaque contact (jour, heure, device) et envoyer au moment optimal POUR LUI. +20% OR.', 'Email predictive: pattern ouverture par contact → envoyer au moment optimal = +20% OR', 'email', 'best_practice', 0.85, 'cosmos', 'system'),
('COSMOS_2: Le commercial solution mapping: pour chaque probleme identifie, preparer 3 solutions (basic, standard, premium). Le client choisit → se sent en controle.', 'Solution mapping: 3 solutions par probleme (basic/standard/premium). Client choisit', 'commercial', 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_3: Le content series engagement: les series (Partie 1, 2, 3) generent 3x plus de follows car les viewers veulent la suite. Planifier des series de 3-5 episodes.', 'Content series 3-5 episodes = 3x follows (viewers veulent suite)', 'content', 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_4: Le SEO E-E-A-T implementation: auteur identifie (photo, bio, credentials) + sources citees + date publication + mises a jour + liens vers autorites = EEAT maximal.', 'EEAT implementation: auteur + sources + dates + MAJ + autorites = maximal', 'seo', 'best_practice', 0.88, 'cosmos', 'system'),
('COSMOS_5: Le ad creative fatigue early warning: CTR baisse 15% sur 3j consecutifs = debut de fatigue. Renouveler dans 48h avant que le CPM n explose.', 'Creative fatigue early: CTR -15% 3j = debut fatigue. Renouveler 48h', 'ads', 'insight', 0.85, 'cosmos', 'system'),
('COSMOS_6: Le DM Instagram conversation nurturing: apres le 1er DM, ne pas pitcher immediatement. 3 messages de valeur (conseil, resource, compliment) avant toute proposition.', 'DM nurturing: 3 messages valeur avant proposition. Pas pitch immediat', 'dm_instagram', 'best_practice', 0.85, 'cosmos', 'system'),
('COSMOS_7: Le WhatsApp retention post-achat: J+1 merci + tips utilisation → J+3 satisfaction check → J+7 demande avis → J+14 offre cross-sell → J+30 programme fidelite.', 'WhatsApp post-achat: J1 tips → J3 satisfaction → J7 avis → J14 cross-sell → J30 fidelite', 'whatsapp', 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_8: Le chatbot micro-conversion tracking: greeting → engaged (pose question) → qualified (repond 2+ questions) → converted (RDV ou achat) → satisfied (CSAT positive).', 'Chatbot funnel: greeting → engaged → qualified → converted → satisfied', 'chatbot', 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_9: Le GMaps local event posting: publier des Google Posts pour chaque evenement local (marche, fete, festival) en lien avec l activite. Visibilite locale maximale.', 'GMaps: posts pour evenements locaux (marche, fete, festival) = visibilite locale max', 'gmaps', 'best_practice', 0.78, 'cosmos', 'system'),
('COSMOS_10: Le TikTok analytics interpretation: completion rate > 50% = contenu captivant. Share rate > 2% = contenu viral potential. Follow rate > 1% = contenu qui fidélise.', 'TikTok analytics: completion>50% captivant, share>2% viral, follow>1% fidélise', 'tiktok_comments', 'insight', 0.82, 'cosmos', 'system'),
('COSMOS_11: Le CEO agent budget allocation formula: ROI agent (resultats/cout) × strategic importance × client satisfaction = budget allocation score. Top agents = plus de budget.', 'CEO budget: ROI × importance × satisfaction = allocation score. Top = plus budget', 'ceo', 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_12: Le retention customer advocacy program: NPS 9-10 → demander temoignage (video si possible) → offrir referral reward → inviter au beta program → customer advisory board.', 'Advocacy: NPS 9-10 → temoignage → referral reward → beta → advisory board', 'retention', 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_13: Le onboarding time-to-value benchmark: SaaS self-serve < 5 min = excellent. 5-15 min = bon. 15-30 min = moyen. > 30 min = probleme. KeiroAI cible < 2 min.', 'TTV: <5min excellent, 5-15 bon, 15-30 moyen, >30 probleme. KeiroAI < 2min', 'onboarding', 'insight', 0.85, 'cosmos', 'system'),
('COSMOS_14: Le comptable monthly financial narrative: pas juste des chiffres mais l HISTOIRE. "MRR +15% grace a 3 upsells Pro" vs "MRR: 5750€". Le contexte > le chiffre.', 'Financial narrative: l histoire derriere les chiffres. Contexte > chiffre brut', 'comptable', 'best_practice', 0.80, 'cosmos', 'system'),
('COSMOS_15: Le RH asynchronous decision-making: documenter la decision dans Notion → donner 24h pour les objections → si aucune objection → decision validee. Rapide et democratique.', 'Async decisions: documenter → 24h objections → aucune = validee. Rapide + democratique', 'rh', 'best_practice', 0.78, 'cosmos', 'system'),
('COSMOS_16: Le marketing brand recall test: demander a 20 personnes du marche cible de nommer 3 marques dans votre categorie. Si pas cite → investir massivement en brand awareness.', 'Brand recall: 20 personnes cible, 3 marques. Pas cite = investir brand awareness', 'marketing', 'best_practice', 0.78, 'cosmos', 'system'),
('COSMOS_17: Le cross-agent task handoff: quand un agent termine une tache (email envoye) → notifier l agent suivant (DM follow-up dans 48h). Pipeline inter-agents automatise.', 'Task handoff: agent termine → notifier agent suivant. Pipeline inter-agents auto', NULL, 'best_practice', 0.85, 'cosmos', 'system'),
('COSMOS_18: Le customer data enrichment progressive: a chaque interaction, collecter 1-2 nouvelles infos (secteur au signup, taille a l onboarding, budget au 1er call). Profil enrichi sans friction.', 'Data enrichment progressif: 1-2 infos/interaction. Profil enrichi sans friction', NULL, 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_19: Le KeiroAI agent expertise depth: chaque agent a maintenant acces a 50+ learnings ultra-specialises dans son domaine ET 200+ learnings transverses partages via le RAG.', 'Agent expertise: 50+ specialises + 200+ transverses via RAG', NULL, 'insight', 0.88, 'cosmos', 'system'),
('COSMOS_20: Le KeiroAI nearing 8000: a ce niveau d intelligence, les recommandations des agents sont basees sur des patterns statistiquement significatifs, pas sur des intuitions.', 'KeiroAI ~8000: recommandations basees sur patterns statistiques, pas intuitions', 'ceo', 'insight', 0.90, 'cosmos', 'system'),
('COSMOS_21: Le email campaign performance grading: A = OR>30% CTR>5% reply>3%. B = OR>20% CTR>3% reply>1%. C = OR>15% CTR>2%. D = OR<15%. F = OR<10%. Grade C minimum acceptable.', 'Email grading: A OR>30%, B OR>20%, C OR>15%, D OR<15%, F OR<10%. Min C', 'email', 'insight', 0.82, 'cosmos', 'system'),
('COSMOS_22: Le commercial pipeline health indicators: velocity (deals avancent), coverage (3x quota), conversion (win rate stable), aging (pas de deals vieux > 30j).', 'Pipeline health: velocity + coverage 3x + conversion stable + aging < 30j', 'commercial', 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_23: Le content creation system elite: 1 journee production/semaine (batch) → planification auto (scheduling tool) → publication auto → analyse vendredi → iteration lundi.', 'Content system: 1j batch → auto-planif → auto-publi → analyse vendredi → iteration lundi', 'content', 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_24: Le SEO site audit checklist complete: indexation (GSC) + vitesse (PageSpeed) + mobile (mobile-friendly test) + schema (rich results test) + links (internal+external) + content (quality+gaps).', 'SEO audit: indexation + vitesse + mobile + schema + links + content', 'seo', 'best_practice', 0.85, 'cosmos', 'system'),
('COSMOS_25: Le ad creative winning formula: hook 0-2s (arret scroll) + probleme 2-5s (identification) + solution 5-10s (produit) + proof 10-13s (temoignage) + CTA 13-15s (action).', 'Creative formula: hook 0-2 + probleme 2-5 + solution 5-10 + proof 10-13 + CTA 13-15', 'ads', 'best_practice', 0.85, 'cosmos', 'system'),
('COSMOS_26: Le DM Instagram prospect scoring real-time: chaque interaction enrichit le score. Like=1pt, comment=3pt, story reaction=5pt, DM reply=10pt, meeting=25pt. > 30 = qualifie.', 'DM scoring: like 1, comment 3, story 5, DM reply 10, meeting 25. > 30 = qualifie', 'dm_instagram', 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_27: Le WhatsApp business efficiency metrics: message delivery rate > 95%, read rate > 70%, response rate > 30%, resolution rate > 60%. Benchmarks a atteindre.', 'WhatsApp metrics: delivery>95%, read>70%, response>30%, resolution>60%', 'whatsapp', 'insight', 0.80, 'cosmos', 'system'),
('COSMOS_28: Le chatbot ROI calculation complete: (tickets evites × cout/ticket) + (leads qualifies × valeur/lead) + (ventes assistees × AOV) + (heures CS economisees × taux horaire) - cout chatbot.', 'Chatbot ROI: tickets evites + leads + ventes + heures CS - cout chatbot', 'chatbot', 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_29: Le GMaps multi-location management: si l entreprise a plusieurs adresses, chaque adresse doit avoir sa propre fiche Google complete et optimisee independamment.', 'GMaps multi-location: fiche complete et optimisee par adresse independamment', 'gmaps', 'best_practice', 0.80, 'cosmos', 'system'),
('COSMOS_30: Le TikTok content recycling strategy: les videos top-performing (top 10%) peuvent etre repostees 3-6 mois plus tard avec un nouveau hook. 70% de la nouvelle audience ne les a pas vues.', 'TikTok recycling: top 10% videos repostees 3-6 mois + nouveau hook. 70% nouvelle audience', 'tiktok_comments', 'best_practice', 0.80, 'cosmos', 'system'),
('COSMOS_31: Le CEO monthly OKR check-in: verifier la progression des 3 OKR trimestriels. Si 1 est en retard → reallouer des resources. Si 2+ en retard → revoir les objectifs.', 'CEO OKR check mensuel: 1 retard = reallouer. 2+ retard = revoir objectifs', 'ceo', 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_32: Le retention save offer hierarchy: 1) education (montrer valeur non decouverte), 2) plan adjustment, 3) temporary discount, 4) pause subscription, 5) personal CS call.', 'Save hierarchy: education → plan adjust → discount → pause → call CS', 'retention', 'best_practice', 0.85, 'cosmos', 'system'),
('COSMOS_33: Le onboarding A/B test priority: tester dans cet ordre: 1) nombre d etapes, 2) ordre des etapes, 3) contenu de chaque etape, 4) design/UX, 5) emails lifecycle.', 'Onboarding A/B priority: etapes nombre → ordre → contenu → design → emails', 'onboarding', 'best_practice', 0.80, 'cosmos', 'system'),
('COSMOS_34: Le comptable expense optimization checklist: auditer chaque abonnement SaaS mensuel. Identifier les outils non utilises (> 30j sans login). Les annuler = -15-25% budget outils.', 'Expense optimization: auditer SaaS. Non utilises >30j = annuler = -15-25% budget', 'comptable', 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_35: Le RH performance review framework: strengths (celebrer) → development areas (2-3 specifiques) → action plan (etapes concretes) → support needed → timeline review.', 'Performance review: strengths → development → action plan → support → timeline', 'rh', 'best_practice', 0.78, 'cosmos', 'system'),
('COSMOS_36: Le marketing campaign post-mortem template: objectif → resultats → CAC → learnings (ce qui a marche, ce qui n a pas marche) → recommendations → next steps.', 'Campaign post-mortem: objectif + resultats + CAC + learnings + reco + next steps', 'marketing', 'best_practice', 0.80, 'cosmos', 'system'),
('COSMOS_37: Le agent collaboration patterns: parallel (email + DM meme prospect) → sequential (contenu → SEO → ads) → conditional (si email echoue → DM fallback) → escalation (agent → CEO).', 'Agent collab patterns: parallel + sequential + conditional + escalation', NULL, 'best_practice', 0.85, 'cosmos', 'system'),
('COSMOS_38: Le customer segmentation multi-dimensional: par valeur (LTV) × par engagement (usage) × par satisfaction (NPS) × par risque (health score) = 16 segments actionables.', 'Segmentation 4D: valeur × engagement × satisfaction × risque = 16 segments', NULL, 'best_practice', 0.82, 'cosmos', 'system'),
('COSMOS_39: Le KeiroAI intelligence compounding: chaque semaine, le RAG grandit de 50-100 nouveaux learnings. En 1 an = 2500-5000 nouveaux. L intelligence s accelere.', 'KeiroAI compounding: +50-100 learnings/sem. 1 an = 2500-5000 nouveaux. S accelere', NULL, 'insight', 0.85, 'cosmos', 'system'),
('COSMOS_40: Le KeiroAI titan vision: 17 agents avec 8000+ learnings, auto-amelioration continue, intelligence collective sans precedent. L avenir du marketing IA est deja la.', 'KeiroAI titan: 17 agents + 8000+ learnings + auto-improve + intelligence collective = avenir', 'ceo', 'best_practice', 0.95, 'cosmos', 'system')
